INSERT INTO `performance_feedback` VALUES (1,10,13,'Manager','H2 2025','Exceptional technical leadership. Consistently delivers high-quality ML solutions. Strong mentoring ability.','Could improve delegation skills. Sometimes takes on too much personally.','Consider leadership coaching program for VP readiness.','Outstanding performer with clear leadership trajectory. Ready for expanded scope.',5,0,'Shared with Employee','2025-12-20','2026-03-07 00:44:17',NULL),(2,10,14,'Peer','H2 2025','Great collaborator. Always willing to help with complex technical challenges. Excellent at explaining difficult concepts.','Can be very detail-oriented which sometimes slows decision-making.','Would benefit from more cross-functional project exposure.','Valued team member who consistently raises the bar for technical excellence.',4,0,'Shared with Employee','2025-12-18','2026-03-07 00:44:17',NULL),(3,10,NULL,'Self','H2 2025','Strong technical depth in ML and data architecture. Effective at stakeholder communication.','Need to improve executive presence in board-level presentations. Should delegate more to develop team.','Planning to take executive communication course and delegate 2 projects to senior team members.','I believe I have made strong progress this year, particularly in team development and technical delivery.',4,0,'Shared with Employee','2025-12-15','2026-03-07 00:44:17',NULL),(4,10,11,'Peer','H2 2025','Innovative problem solver. Brought fresh perspectives to our data pipeline challenges.','Could engage more in team social activities and informal knowledge sharing.','Host monthly lunch-and-learn sessions.','A reliable and talented colleague who elevates the entire team.',4,1,'Shared with Employee','2025-12-22','2026-03-07 00:44:17',NULL),(5,10,12,'360 Degree','H2 2025','Demonstrates strong business acumen alongside technical expertise. Vision for ML strategy is excellent.','Needs to balance technical depth with strategic communication for senior leadership.','Enroll in executive MBA module or strategic leadership program.','High-potential leader ready for next-level challenges.',5,0,'Shared with Employee','2025-12-25','2026-03-07 00:44:17',NULL),(6,10,11,'Peer','H1 2025','Collaborative team player. Excellent at knowledge sharing.','Could be more assertive in meetings.','Take on more visible cross-team initiatives.','Reliable colleague.',4,0,'Shared with Employee','2025-06-15',NULL,NULL),(7,10,12,'Peer','H1 2025','Strong analytical skills. Great at problem decomposition.','Documentation could be more thorough.','Consider mentoring junior developers.','An asset to any project team.',5,0,'Shared with Employee','2025-06-18',NULL,NULL),(8,10,13,'Manager','H1 2025','Exceeds expectations in technical delivery. Strong stakeholder management.','Needs to improve delegation skills.','Recommend for senior leadership program.','High performer ready for next level.',5,0,'Shared with Employee','2025-06-20',NULL,NULL),(9,10,NULL,'Self','H1 2025','Good at building consensus. Strong technical foundation.','Need to work on time management under pressure.','Planning project management certification.','Solid progress on yearly goals.',4,0,'Shared with Employee','2025-06-10',NULL,NULL),(10,10,14,'360 Degree','H1 2025','Forward-thinking technology adoption. Inspires team confidence.','Could improve communication with remote team.','Regular virtual coffee chats with distributed team.','Well-rounded professional.',4,0,'Shared with Employee','2025-06-22',NULL,NULL),(12,0,10,'Peer','2026','test','impor','sugg','comm',3,0,'',NULL,NULL,NULL);
