h metrics',25.00,'Completed',100,100,'2025-01-10 09:00:00',NULL),(11,10,'AWS ML Specialty Certification','Obtain AWS Machine Learning Specialty certification','Technical','2024-01-01','2024-06-30','Certification','Certification obtained',25.00,'Completed',100,100,'2024-01-05 09:00:00',NULL),(12,10,'Lead Team of 8','Successfully lead and manage team of 8 engineers','Leadership','2024-01-01','2024-12-31','Team performance','Team KPIs met, retention 100%',25.00,'Completed',100,100,'2024-01-05 09:00:00',NULL),(13,10,'Deliver 2 ML Projects','Deliver 2 major ML projects on time and within budget','Technical','2024-01-01','2024-12-31','2 projects','Projects delivered meeting all success criteria',25.00,'Completed',100,100,'2024-01-05 09:00:00',NULL),(14,10,'Reduce Model Training Time','Optimize ML pipeline to reduce model training time by 40%','Technical','2024-03-01','2024-12-31','40% reduction','Training time measured before/after',25.00,'Completed',100,100,'2024-01-05 09:00:00',NULL),(18,10,'tsy','jhbn','Leadership','2026-03-10','2026-03-26','test','test',50.00,'In Progress',50,NULL,NULL,NULL);
